import { SpinnerIcon } from "@phosphor-icons/react";
import * as stylex from "@stylexjs/stylex";
import type React from "react";
import { spinnerStyles } from "./spinner.styles";
import type { PropsWithStylex } from "@blenx-ui/ui/utils/stylex.utils";

type Props = PropsWithStylex<React.ComponentProps<typeof SpinnerIcon>>;

export function Spinner({ style, ...props }: Props): React.ReactElement {
  return (
    <SpinnerIcon
      aria-label="Loading"
      role="status"
      {...stylex.props(spinnerStyles.spinner, style)}
      {...props}
    />
  );
}

import * as stylex from "@stylexjs/stylex";

export const spin = stylex.keyframes({
  from: {
    transform: "rotate(0deg)",
  },
  to: {
    transform: "rotate(360deg)",
  },
});

export const spinnerStyles = stylex.create({
  spinner: {
    animationName: spin,
    animationDuration: "1s",
    animationIterationCount: "infinite",
    animationTimingFunction: "linear",
  },
});
